/**
 * ArvoHybridPopover — vanilla JS implementation.
 *
 * Composes ArvoPopover internally for chrome (header, footer, body, positioning,
 * overlay registration, focus trap, transitions). HybridPopover renders the
 * structured filter-list content variants (multi-select, single-select,
 * reorder-only) inside the Popover's stickyHeader and content slots.
 *
 * See descriptors/hybrid-popover.json and the React parity reference at
 * packages/react/src/components/HybridPopover/HybridPopover.tsx.
 */

import {
  createSortableList,
  createResizeHandle,
  createTabRoving,
  filterItems,
  filterGroups,
} from '@arvo/core';
import type {
  SortableHandle,
  ResizeHandleInstance,
  TabRoving,
} from '@arvo/core';

import { ArvoPopover } from '../Popover/Popover';
import type {
  ArvoPopoverActionConfig,
  ArvoPopoverHeaderActionConfig,
} from '../Popover/Popover';
import { ArvoSearch } from '../Search/Search';
import { ArvoCheckbox } from '../Checkbox/Checkbox';
import { ArvoRadio } from '../Radio/Radio';
import { ArvoButton } from '../Button/Button';
import { ArvoIconButton } from '../IconButton/IconButton';
import { ArvoButtonGroup } from '../ButtonGroup/ButtonGroup';

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

export const HPOP_MIN_WIDTH = 280;
export const HPOP_DEFAULT_WIDTH = 320;
export const HPOP_MAX_WIDTH = 500;
export const HPOP_MIN_HEIGHT = 272;

const SKELETON_ROW_COUNT = 12;

// ---------------------------------------------------------------------------
// Custom types (parity with React)
// ---------------------------------------------------------------------------

export interface HybridPopoverItem {
  id: string;
  label: string;
  secondaryLabel?: string;
  icon?: string;
  value?: unknown;
  isDisabled?: boolean;
  isExcluded?: boolean;
  isDraggable?: boolean;
  hasInline?: boolean | HybridPopoverItem[] | HybridPopoverInlineConfig;
  isIndeterminate?: boolean;
}

export interface HybridPopoverGroup {
  id: string;
  label?: string;
  isDraggable?: boolean;
  hasSelectAll?: boolean;
  items: HybridPopoverItem[];
}

export interface HybridPopoverSearchConfig {
  variant?: 'default' | 'filter-search';
  placeholder?: string;
  shortcut?: string;
  counter?: boolean;
}

export interface HybridPopoverConditionalConfig {
  value: 'and' | 'or';
  onChange: (value: 'and' | 'or') => void;
}

export interface HybridPopoverEmptyConfig {
  noDataTitle?: string;
  noDataMessage?: string;
  noResultsTitle?: string;
  noResultsMessage?: string;
  noResultsClearLabel?: string;
}

export interface HybridPopoverInlineConfig {
  title?: string;
  items?: HybridPopoverItem[] | HybridPopoverGroup[];
  variant?: 'multi' | 'single';
  hasBackButton?: boolean;
}

export interface HybridPopoverReorderDetail {
  fromIndex: number;
  toIndex: number;
  fromGroup: string | null;
  toGroup: string | null;
  items: HybridPopoverItem[] | HybridPopoverGroup[];
}

export interface HybridPopoverChangeMeta {
  item: HybridPopoverItem | null;
  action: 'toggle' | 'select-all' | 'group-select-all' | 'apply' | 'reset' | 'clear';
}

export type HybridPopoverVariant =
  | 'multi'
  | 'single'
  | 'boolean'
  | 'conditional'
  | 'custom';

export type HybridPopoverSelectionMode = 'multi' | 'single' | 'none';

// ---------------------------------------------------------------------------
// Options
// ---------------------------------------------------------------------------

export interface ArvoHybridPopoverOptions {
  variant?: HybridPopoverVariant;
  selectionMode?: HybridPopoverSelectionMode;
  /** Controlled item ordering. */
  items?: HybridPopoverItem[] | HybridPopoverGroup[];
  /** Initial items for uncontrolled order management (drag persists internally). */
  defaultItems?: HybridPopoverItem[] | HybridPopoverGroup[];
  value?: string[] | string | null;
  defaultValue?: string[] | string | null;
  onChange?: (
    value: string[] | string | null,
    meta: HybridPopoverChangeMeta,
  ) => void;
  commitOn?: 'apply' | 'change';

  search?: false | HybridPopoverSearchConfig;
  conditional?: false | HybridPopoverConditionalConfig;

  hasGlobalSelectAll?: boolean;
  enableReorder?: boolean;
  crossGroupDrag?: boolean;
  onReorder?: (detail: HybridPopoverReorderDetail) => void;

  emptyConfig?: HybridPopoverEmptyConfig;
  actions?: ArvoPopoverActionConfig[] | false;

  isResizable?: boolean;
  width?: number;
  height?: number | null;
  onResize?: (detail: { width: number; height: number }) => void;
  onResizeCommit?: (detail: { width: number; height: number }) => void;

  title?: string | null;
  hasHeader?: boolean;
  isClosable?: boolean;
  hasBackButton?: boolean;
  onBack?: () => void;
  headerActions?: ArvoPopoverHeaderActionConfig[];

  placement?: ArvoPopoverOptionsPlacement;
  offset?: number;
  closeOnOutside?: boolean;

  isLoading?: boolean;
  defaultOpen?: boolean;

  isInline?: boolean;
  parent?: string | null;

  onApply?: (value: string[] | string | null) => boolean | void;
  onCancel?: () => void;
  onReset?: () => void;
  onOpen?: () => boolean | void;
  onClose?: () => boolean | void;
}

type ArvoPopoverOptionsPlacement =
  | 'top' | 'top-start' | 'top-end'
  | 'bottom' | 'bottom-start' | 'bottom-end'
  | 'left' | 'left-start' | 'left-end'
  | 'right' | 'right-start' | 'right-end'
  | 'auto';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function isGrouped(
  items: HybridPopoverItem[] | HybridPopoverGroup[],
): items is HybridPopoverGroup[] {
  return items.length > 0 && 'items' in (items[0] as object);
}

function flattenItems(
  items: HybridPopoverItem[] | HybridPopoverGroup[],
): HybridPopoverItem[] {
  if (isGrouped(items)) return items.flatMap((g) => g.items);
  return items as HybridPopoverItem[];
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

function resolveSelection(
  variant: HybridPopoverVariant,
  selectionMode: HybridPopoverSelectionMode | undefined,
): HybridPopoverSelectionMode {
  if (selectionMode) return selectionMode;
  if (variant === 'multi') return 'multi';
  if (variant === 'single') return 'single';
  return 'multi';
}

function defaultDraft(
  selection: HybridPopoverSelectionMode,
  seedValue: string[] | string | null | undefined,
): string[] | string | null {
  const seed = seedValue ?? null;
  if (selection === 'multi') {
    return Array.isArray(seed) ? [...seed] : [];
  }
  if (selection === 'single') {
    return typeof seed === 'string' ? seed : null;
  }
  return null;
}

function valuesEqual(
  a: string[] | string | null,
  b: string[] | string | null,
): boolean {
  if (a === b) return true;
  if (Array.isArray(a) && Array.isArray(b)) {
    if (a.length !== b.length) return false;
    return a.every((v, i) => v === b[i]);
  }
  return false;
}

function cloneValue(
  v: string[] | string | null,
): string[] | string | null {
  if (Array.isArray(v)) return [...v];
  return v;
}

/**
 * Apply a sortable-list commit (global fromIndex / toIndex with
 * fromGroup / toGroup) to an items array. Mirrors the React parity helper.
 */
function applyReorder(
  items: HybridPopoverItem[] | HybridPopoverGroup[],
  fromIndex: number,
  toIndex: number,
  fromGroup: string | null,
  toGroup: string | null,
): HybridPopoverItem[] | HybridPopoverGroup[] {
  if (!isGrouped(items)) {
    const arr = [...(items as HybridPopoverItem[])];
    if (fromIndex < 0 || fromIndex >= arr.length) return items;
    const [moved] = arr.splice(fromIndex, 1);
    const insertIdx = clamp(toIndex, 0, arr.length);
    arr.splice(insertIdx, 0, moved);
    return arr;
  }
  const groups = items as HybridPopoverGroup[];
  const flat: { item: HybridPopoverItem; groupId: string }[] = [];
  groups.forEach((g) =>
    g.items.forEach((it) => flat.push({ item: it, groupId: g.id })),
  );
  if (fromIndex < 0 || fromIndex >= flat.length) return items;
  const [moved] = flat.splice(fromIndex, 1);
  const targetGroupId = toGroup ?? fromGroup ?? moved.groupId;
  moved.groupId = targetGroupId;
  const insertIdx = clamp(toIndex, 0, flat.length);
  flat.splice(insertIdx, 0, moved);
  return groups.map((g) => ({
    ...g,
    items: flat.filter((entry) => entry.groupId === g.id).map((e) => e.item),
  }));
}

const EMPTY_DEFAULTS: Required<HybridPopoverEmptyConfig> = {
  noDataTitle: 'No data available',
  noDataMessage: 'Adjust your filter search query.',
  noResultsTitle: 'No results found',
  noResultsMessage: 'Adjust your filter search query.',
  noResultsClearLabel: 'Clear Search',
};

// ---------------------------------------------------------------------------
// Class
// ---------------------------------------------------------------------------

let _idCounter = 0;

export class ArvoHybridPopover {
  private _trigger: HTMLElement | null;
  private _options: ArvoHybridPopoverOptions;

  private _id: string;
  private _selection: HybridPopoverSelectionMode;

  private _items: HybridPopoverItem[] | HybridPopoverGroup[];
  private _committed: string[] | string | null;
  private _draft: string[] | string | null;
  private _query = '';
  private _isLoading: boolean;

  // Inner Popover composition
  private _popover: ArvoPopover | null = null;
  private _panelEl: HTMLElement | null = null;

  // Slot containers (we own these and re-render into them)
  private _stickyEl: HTMLDivElement | null = null;
  private _bodyEl: HTMLDivElement | null = null;

  // Inner instances tracked for teardown
  private _searchInstance: ArvoSearch | null = null;
  private _conditionalInstance: ArvoButtonGroup | null = null;
  private _globalSAInstance: ArvoCheckbox | null = null;
  private _groupSAInstances: ArvoCheckbox[] = [];
  private _itemInstances: (ArvoCheckbox | ArvoRadio)[] = [];
  private _chevInstances: ArvoIconButton[] = [];
  private _clearSearchInstance: ArvoButton | null = null;

  // Adapters
  private _sortable: SortableHandle | null = null;
  private _resize: ResizeHandleInstance | null = null;
  private _roving: TabRoving | null = null;

  // Items ownership: true when caller passed `items`, false when uncontrolled
  // (defaultItems supplied or items omitted) — uncontrolled mode mutates the
  // internal array on drag commit.
  private _isControlledItems: boolean;

  // Resize state — seeded from options and persisted across opens.
  private _resizedWidth: number;
  private _resizedHeight: number | null;

  // Bound listeners
  private _boundOnPopoverOpen: (e: Event) => void;
  private _boundOnPopoverClose: (e: Event) => void;

  static initialize(
    element: HTMLElement,
    options?: ArvoHybridPopoverOptions,
  ): ArvoHybridPopover {
    return new ArvoHybridPopover(element, options);
  }

  constructor(element: HTMLElement, options?: ArvoHybridPopoverOptions) {
    this._trigger = element;
    this._options = { ...(options ?? {}) };

    this._id = `arvo-hpop-${++_idCounter}`;

    const variant: HybridPopoverVariant = this._options.variant ?? 'multi';
    this._selection = resolveSelection(variant, this._options.selectionMode);

    if (
      variant === 'boolean' ||
      variant === 'conditional' ||
      variant === 'custom'
    ) {
      console.warn(
        `HybridPopover: variant "${variant}" is not yet implemented.`,
      );
    }

    this._isControlledItems =
      this._options.items !== undefined &&
      this._options.defaultItems === undefined;
    this._items =
      this._options.items ??
      this._options.defaultItems ??
      [];
    this._isLoading = !!this._options.isLoading;

    this._resizedWidth = clamp(
      this._options.width ?? HPOP_DEFAULT_WIDTH,
      HPOP_MIN_WIDTH,
      HPOP_MAX_WIDTH,
    );
    this._resizedHeight = this._options.height ?? null;

    // Seed committed/draft from value or defaultValue.
    const seedRaw =
      this._options.value !== undefined
        ? this._options.value
        : this._options.defaultValue ?? null;
    this._committed = defaultDraft(this._selection, seedRaw);
    this._draft = defaultDraft(this._selection, this._committed);

    // Build slot containers.
    this._stickyEl = document.createElement('div');
    this._stickyEl.className = 'arvo-hpop__sticky';

    this._bodyEl = document.createElement('div');
    this._bodyEl.className = 'arvo-hpop__body-root';

    // Compose ArvoPopover.
    this._popover = new ArvoPopover(element, {
      variant: 'edge',
      title: this._options.title ?? '',
      hasHeader: this._options.hasHeader ?? true,
      isClosable: this._options.isClosable ?? true,
      hasBackButton: this._options.hasBackButton ?? false,
      onBack: this._options.onBack,
      headerActions: this._options.headerActions ?? [],
      placement: (this._options.placement ?? 'auto') as ArvoPopoverOptionsPlacement,
      offset: this._options.offset ?? 2,
      closeOnOutside: this._options.closeOnOutside ?? true,
      isLoading: this._isLoading,
      isInline: this._options.isInline ?? false,
      stickyHeader: this._stickyEl,
      content: this._bodyEl,
      actions: this._buildPopoverActions(),
      hasFooter: true,
      onOpen: () => this._options.onOpen?.(),
      onClose: () => this._options.onClose?.(),
    });

    // Resolve panel element via aria-controls (set by Popover constructor).
    const panelId = element.getAttribute('aria-controls');
    if (panelId) {
      this._panelEl = document.getElementById(panelId);
    }
    this._applyPanelClasses();

    // Wire popover lifecycle events to dispatch our own + (de)mount adapters.
    this._boundOnPopoverOpen = this._handlePopoverOpen.bind(this);
    this._boundOnPopoverClose = this._handlePopoverClose.bind(this);
    element.addEventListener('popover:open', this._boundOnPopoverOpen);
    element.addEventListener('popover:close', this._boundOnPopoverClose);

    // Initial render of slots.
    this._renderSticky();
    this._renderBody();

    // Loading state may need footer hidden immediately.
    if (this._isLoading) {
      this._popover.setFooterVisible(false);
    }

    // Honor defaultOpen.
    if (this._options.defaultOpen) {
      // Defer so the panel is fully connected before computing position.
      queueMicrotask(() => this.open());
    }
  }

  // ---------------------------------------------------------------------------
  // Public API
  // ---------------------------------------------------------------------------

  open(): void {
    this._popover?.open();
  }

  close(): void {
    this._popover?.close();
  }

  isOpen(): boolean {
    return this._popover?.isOpen() ?? false;
  }

  toggle(): void {
    this._popover?.toggle();
  }

  value(): string[] | string | null;
  value(newValue: string[] | string | null): void;
  value(
    newValue?: string[] | string | null,
  ): string[] | string | null | void {
    if (newValue === undefined) {
      return cloneValue(this._committed);
    }
    const prev = this._committed;
    this._committed = cloneValue(newValue);
    this._draft = defaultDraft(this._selection, this._committed);
    this._renderBody();
    if (!valuesEqual(this._committed, prev)) {
      this._fireChange(this._committed, { item: null, action: 'apply' });
    }
  }

  setLoading(loading: boolean): void {
    if (this._isLoading === loading) return;
    this._isLoading = loading;
    this._popover?.setLoading(loading);
    this._popover?.setFooterVisible(!loading);
    this._renderSticky();
    this._renderBody();
    this._applyPanelClasses();
    // Mount/unmount sortable + roving based on loading state.
    if (loading) {
      this._teardownSortable();
      this._teardownRoving();
    } else if (this.isOpen()) {
      this._mountSortable();
      this._mountRoving();
    }
  }

  updateItems(items: HybridPopoverItem[] | HybridPopoverGroup[]): void {
    this._items = items;
    this._renderSticky();
    this._renderBody();
    this._applyPanelClasses();
    if (this.isOpen()) {
      this._teardownSortable();
      this._mountSortable();
      this._teardownRoving();
      this._mountRoving();
    }
  }

  reposition(): void {
    this._popover?.reposition();
  }

  destroy(): void {
    const trigger = this._trigger;
    if (trigger) {
      trigger.removeEventListener('popover:open', this._boundOnPopoverOpen);
      trigger.removeEventListener('popover:close', this._boundOnPopoverClose);
    }
    this._teardownSortable();
    this._teardownResize();
    this._teardownRoving();
    this._destroyInnerInstances();
    this._popover?.destroy();
    this._popover = null;
    this._stickyEl?.remove();
    this._bodyEl?.remove();
    this._stickyEl = null;
    this._bodyEl = null;
    this._panelEl = null;
    this._trigger = null;
  }

  // ---------------------------------------------------------------------------
  // Popover lifecycle wiring
  // ---------------------------------------------------------------------------

  private _handlePopoverOpen(): void {
    // Reset draft from committed; reset query.
    this._draft = defaultDraft(this._selection, this._committed);
    this._query = '';
    this._renderSticky();
    this._renderBody();
    this._applyPanelClasses();
    this._applyDimensions();
    this._mountSortable();
    this._mountResize();
    this._mountRoving();
    this._dispatchEvent('hpop:open', {});
  }

  private _handlePopoverClose(): void {
    this._teardownSortable();
    this._teardownResize();
    this._teardownRoving();
    this._dispatchEvent('hpop:close', {});
  }

  // ---------------------------------------------------------------------------
  // Panel chrome
  // ---------------------------------------------------------------------------

  private _applyPanelClasses(): void {
    const panel = this._panelEl;
    if (!panel) return;

    const variant = this._options.variant ?? 'multi';
    const searchEnabled = this._options.search !== false;
    const conditional = this._options.conditional;
    const isResizable = this._options.isResizable ?? true;

    const flatAll = flattenItems(this._items);
    const totalCount = flatAll.length;
    const filteredCount = this._getFilteredItems().__filteredCount;

    // Remove any prior hpop classes we set.
    const toRemove: string[] = [];
    panel.classList.forEach((c) => {
      if (c.startsWith('arvo-hpop')) toRemove.push(c);
    });
    toRemove.forEach((c) => panel.classList.remove(c));

    panel.classList.add('arvo-hpop');
    panel.classList.add(`arvo-hpop--${variant}`);
    if (searchEnabled) panel.classList.add('arvo-hpop--with-search');
    if (this._selection === 'multi' && conditional) {
      panel.classList.add('arvo-hpop--with-conditional');
    }
    if (isResizable) panel.classList.add('arvo-hpop--with-resize');

    if (totalCount === 0) panel.classList.add('arvo-hpop--no-data');
    else if (filteredCount === 0) panel.classList.add('arvo-hpop--no-results');

    if (this._isLoading) panel.classList.add('loading');
  }

  private _applyDimensions(): void {
    const panel = this._panelEl;
    if (!panel) return;
    // Width is sourced from internal state which is seeded once from
    // options and updated by createResizeHandle. Subsequent opens preserve
    // user-resized dims.
    panel.style.width = `${clamp(
      this._resizedWidth,
      HPOP_MIN_WIDTH,
      HPOP_MAX_WIDTH,
    )}px`;
    if (this._resizedHeight != null) {
      const maxH = Math.floor(window.innerHeight * 0.9);
      panel.style.height = `${clamp(
        this._resizedHeight,
        HPOP_MIN_HEIGHT,
        maxH,
      )}px`;
    } else {
      panel.style.removeProperty('height');
    }
  }

  // ---------------------------------------------------------------------------
  // Filtering
  // ---------------------------------------------------------------------------

  private _getFilteredItems(): {
    filtered: HybridPopoverItem[] | HybridPopoverGroup[];
    flatFiltered: HybridPopoverItem[];
    flatAll: HybridPopoverItem[];
    grouped: boolean;
    __filteredCount: number;
  } {
    const items = this._items;
    const grouped = isGrouped(items);
    const searchEnabled = this._options.search !== false;
    const query = this._query;

    let filtered: HybridPopoverItem[] | HybridPopoverGroup[];
    if (!searchEnabled || !query) {
      filtered = items;
    } else if (grouped) {
      filtered = filterGroups(items as HybridPopoverGroup[], {
        query,
        keys: ['label', 'secondaryLabel'],
      }) as HybridPopoverGroup[];
    } else {
      filtered = filterItems(items as HybridPopoverItem[], {
        query,
        keys: ['label', 'secondaryLabel'],
      }) as HybridPopoverItem[];
    }

    const flatFiltered = flattenItems(filtered);
    const flatAll = flattenItems(items);
    return {
      filtered,
      flatFiltered,
      flatAll,
      grouped,
      __filteredCount: flatFiltered.length,
    };
  }

  // ---------------------------------------------------------------------------
  // Sticky header (search + conditional)
  // ---------------------------------------------------------------------------

  private _renderSticky(): void {
    const sticky = this._stickyEl;
    if (!sticky) return;

    // Tear down previous inner instances.
    this._searchInstance?.destroy();
    this._searchInstance = null;
    this._conditionalInstance?.destroy();
    this._conditionalInstance = null;
    sticky.textContent = '';

    if (this._isLoading) {
      sticky.style.display = 'none';
      return;
    }

    const searchEnabled = this._options.search !== false;
    const conditional = this._options.conditional;
    const showSearch = searchEnabled;
    const showConditional = this._selection === 'multi' && !!conditional;

    const flatAll = flattenItems(this._items);
    const totalCount = flatAll.length;

    // No-data state hides the sticky header (parity with React).
    if (totalCount === 0 || (!showSearch && !showConditional)) {
      sticky.style.display = 'none';
      return;
    }

    sticky.style.display = '';

    if (showSearch) {
      const searchWrap = document.createElement('div');
      searchWrap.className = 'arvo-hpop__search';

      const searchEl = document.createElement('div');
      searchWrap.appendChild(searchEl);

      const searchCfg: HybridPopoverSearchConfig =
        searchEnabled && this._options.search
          ? (this._options.search as HybridPopoverSearchConfig)
          : {};
      const placeholder = searchCfg.placeholder ?? 'Search';
      const shortcut = searchCfg.shortcut ?? null;
      const showCounter = !!searchCfg.counter && !!this._query;
      const counter = showCounter
        ? {
            current: this._getFilteredItems().__filteredCount,
            total: totalCount,
          }
        : null;

      this._searchInstance = ArvoSearch.initialize(searchEl as HTMLDivElement, {
        variant: 'filter',
        value: this._query,
        placeholder,
        shortcut: shortcut ?? undefined,
        counter,
        isFullWidth: true,
        'aria-label': 'Filter options',
        onChange: (value: string) => this._handleSearchInput(value),
        onSearch: (value: string) => this._handleSearchInput(value),
        onClear: () => this._handleSearchClear(),
      });

      sticky.appendChild(searchWrap);
    }

    if (showConditional && conditional) {
      const condWrap = document.createElement('div');
      condWrap.className = 'arvo-hpop__cond';

      const condEl = document.createElement('div');
      condWrap.appendChild(condEl);

      this._conditionalInstance = ArvoButtonGroup.initialize(condEl, {
        ariaLabel: 'Combine filters',
        items: [
          { value: 'and', label: 'And' },
          { value: 'or', label: 'Or' },
        ],
        value: conditional.value,
        size: 'sm',
        onChange: (detail) => {
          const v = detail.value;
          if (v === 'and' || v === 'or') conditional.onChange(v);
        },
      });

      sticky.appendChild(condWrap);
    }
  }

  // ---------------------------------------------------------------------------
  // Body (skeleton | empty | filter list)
  // ---------------------------------------------------------------------------

  private _renderBody(): void {
    const body = this._bodyEl;
    if (!body) return;

    // Tear down previous inner instances inside the body.
    this._destroyBodyInstances();
    body.textContent = '';

    if (this._isLoading) {
      const list = document.createElement('div');
      list.className = 'arvo-hpop__list';
      list.setAttribute('aria-hidden', 'true');
      for (let i = 0; i < SKELETON_ROW_COUNT; i++) {
        const row = document.createElement('div');
        row.className = 'arvo-hpop__skeleton';
        list.appendChild(row);
      }
      body.appendChild(list);
      return;
    }

    const variant = this._options.variant ?? 'multi';
    const isUnimplemented =
      variant === 'boolean' || variant === 'conditional' || variant === 'custom';

    const { filtered, flatAll, grouped, __filteredCount } =
      this._getFilteredItems();
    const totalCount = flatAll.length;

    if (totalCount === 0) {
      body.appendChild(this._buildEmptyState('no-data'));
      return;
    }

    if (__filteredCount === 0) {
      body.appendChild(this._buildEmptyState('no-results'));
      return;
    }

    if (isUnimplemented) {
      // Empty body for unimplemented variants (parity with React).
      return;
    }

    body.appendChild(this._buildFilterList(filtered, grouped));
  }

  private _buildEmptyState(kind: 'no-data' | 'no-results'): HTMLElement {
    const cfg: Required<HybridPopoverEmptyConfig> = {
      ...EMPTY_DEFAULTS,
      ...(this._options.emptyConfig ?? {}),
    };

    const wrap = document.createElement('div');
    wrap.className = `arvo-hpop__empty arvo-hpop__empty--${kind}`;
    wrap.setAttribute('role', 'status');

    const illus = document.createElement('span');
    illus.className =
      kind === 'no-results'
        ? 'arvo-hpop__empty-illus o9illus o9illus-no-results-found'
        : 'arvo-hpop__empty-illus o9illus o9illus-no-filters-found';
    illus.setAttribute('aria-hidden', 'true');
    wrap.appendChild(illus);

    const titleEl = document.createElement('span');
    titleEl.className = 'arvo-hpop__empty-title';
    titleEl.textContent =
      kind === 'no-results' ? cfg.noResultsTitle : cfg.noDataTitle;
    wrap.appendChild(titleEl);

    const msgEl = document.createElement('span');
    msgEl.className = 'arvo-hpop__empty-msg';
    msgEl.textContent =
      kind === 'no-results' ? cfg.noResultsMessage : cfg.noDataMessage;
    wrap.appendChild(msgEl);

    if (kind === 'no-results') {
      const actionWrap = document.createElement('span');
      actionWrap.className = 'arvo-hpop__empty-action';
      const btnEl = document.createElement('button') as HTMLButtonElement;
      this._clearSearchInstance = ArvoButton.initialize(btnEl, {
        label: cfg.noResultsClearLabel,
        variant: 'outline',
        size: 'sm',
        onClick: () => this._handleSearchClear(),
      });
      actionWrap.appendChild(btnEl);
      wrap.appendChild(actionWrap);
    }

    return wrap;
  }

  // ---------------------------------------------------------------------------
  // Filter list
  // ---------------------------------------------------------------------------

  private _buildFilterList(
    items: HybridPopoverItem[] | HybridPopoverGroup[],
    grouped: boolean,
  ): HTMLElement {
    const list = document.createElement('div');
    list.className = 'arvo-hpop__list';
    const listRole = this._selection === 'none' ? 'group' : 'listbox';
    list.setAttribute('role', listRole);
    list.setAttribute(
      'aria-label',
      this._options.title ?? 'Filter options',
    );
    if (this._selection === 'multi') {
      list.setAttribute('aria-multiselectable', 'true');
    }

    const enableReorder = !!this._options.enableReorder;
    const flatAll = flattenItems(this._items);
    const hasAnyDragHandle =
      enableReorder && flatAll.some((i) => i.isDraggable !== false);

    const isMulti = this._selection === 'multi';
    const draftArr = isMulti && Array.isArray(this._draft) ? this._draft : [];

    // Global select-all (multi only).
    if (isMulti && this._options.hasGlobalSelectAll) {
      const flat = flattenItems(items);
      const sa = this._buildSelectAllRow(
        flat,
        draftArr,
        'Select all',
        false,
        () => this._handleToggleGlobalSelectAll(),
      );
      if (sa) list.appendChild(sa);
    }

    if (grouped) {
      const groups = items as HybridPopoverGroup[];
      groups.forEach((group, gi) => {
        const groupDraggable = enableReorder && group.isDraggable !== false;

        const grpEl = document.createElement('div');
        grpEl.className = 'arvo-hpop__grp';
        grpEl.setAttribute('data-group', group.id);

        if (gi > 0) {
          const div = document.createElement('div');
          div.className = 'arvo-hpop__divider';
          div.setAttribute('role', 'separator');
          grpEl.appendChild(div);
        }

        if (group.label) {
          const hdr = document.createElement('div');
          hdr.className = 'arvo-hpop__grp-hdr';
          hdr.textContent = group.label;
          grpEl.appendChild(hdr);
        }

        if (isMulti && group.hasSelectAll) {
          const sa = this._buildSelectAllRow(
            group.items,
            draftArr,
            `Select all ${group.label ?? ''}`.trim(),
            true,
            () => this._handleToggleGroupSelectAll(group),
          );
          if (sa) grpEl.appendChild(sa);
        }

        for (const item of group.items) {
          const itemDraggable = groupDraggable && item.isDraggable !== false;
          grpEl.appendChild(
            this._buildOptionRow(item, group.id, itemDraggable, hasAnyDragHandle),
          );
        }
        list.appendChild(grpEl);
      });
    } else {
      for (const item of items as HybridPopoverItem[]) {
        const itemDraggable = enableReorder && item.isDraggable !== false;
        list.appendChild(
          this._buildOptionRow(item, null, itemDraggable, hasAnyDragHandle),
        );
      }
    }

    return list;
  }

  private _buildSelectAllRow(
    items: HybridPopoverItem[],
    draftArr: string[],
    label: string,
    isGroupRow: boolean,
    onToggle: () => void,
  ): HTMLElement | null {
    const enabled = items.filter((i) => !i.isDisabled);
    if (enabled.length === 0) return null;
    const draftSet = new Set(draftArr);
    const selectedCount = enabled.filter((i) => draftSet.has(i.id)).length;
    const isChecked = selectedCount === enabled.length;
    const isIndeterminate = selectedCount > 0 && selectedCount < enabled.length;

    const row = document.createElement('div');
    row.className = isGroupRow
      ? 'arvo-hpop__sa arvo-hpop__sa--group'
      : 'arvo-hpop__sa';
    row.setAttribute('role', 'option');
    row.tabIndex = -1;
    row.setAttribute('aria-selected', String(isChecked));
    row.setAttribute('data-sa', isGroupRow ? 'group' : 'global');

    const cbEl = document.createElement('span');
    const cb = ArvoCheckbox.initialize(cbEl, {
      size: 'sm',
      isChecked,
      isIndeterminate,
      isDisabled: false,
      onChange: () => onToggle(),
    });
    cbEl.setAttribute('aria-label', label || 'Select all');
    row.appendChild(cbEl);

    // External label span — keeps 14px typography parity with __opt__lbl
    // instead of the 12px label baked into <ArvoCheckbox label="…">.
    const lblEl = document.createElement('span');
    lblEl.className = 'arvo-hpop__sa__lbl';
    lblEl.textContent = label || 'Select all';
    lblEl.addEventListener('click', () => onToggle());
    row.appendChild(lblEl);

    row.addEventListener('keydown', (event) => {
      if (event.key !== ' ' && event.key !== 'Enter') return;
      event.preventDefault();
      onToggle();
    });

    if (isGroupRow) {
      this._groupSAInstances.push(cb);
    } else {
      this._globalSAInstance = cb;
    }
    return row;
  }

  private _buildOptionRow(
    item: HybridPopoverItem,
    groupId: string | null,
    isDraggable: boolean,
    hasAnyDragHandle: boolean,
  ): HTMLElement {
    const showCheckSlot = this._selection !== 'none';
    const isMulti = this._selection === 'multi';
    const isChecked = this._isItemChecked(item);
    const itemDisabled = !!item.isDisabled;
    const showExclude = isMulti && !!item.isExcluded;
    const showInline = !!item.hasInline;

    // Row role tracks the parent list container's role: `option` lives
    // under `listbox`; when selectionMode='none' the list container is
    // `group`, so each row is a plain `listitem` (aria-selected omitted).
    const rowRole = this._selection === 'none' ? 'listitem' : 'option';

    const row = document.createElement('div');
    row.className = 'arvo-hpop__opt';
    row.setAttribute('role', rowRole);
    row.tabIndex = -1;
    if (rowRole === 'option' && showCheckSlot) {
      row.setAttribute('aria-selected', String(isChecked));
    }
    if (itemDisabled) row.setAttribute('aria-disabled', 'true');
    row.setAttribute('data-id', item.id);
    if (groupId) row.setAttribute('data-group', groupId);

    if (isDraggable) {
      const drag = document.createElement('span');
      drag.className = 'arvo-hpop__opt__drag';
      drag.setAttribute('role', 'button');
      // Drag handle is removed from the tab order — the row owns the
      // single Tab stop via roving tabindex. Keyboard reorder remains
      // available via Ctrl+ArrowUp/Down on the active option.
      drag.tabIndex = -1;
      drag.setAttribute('aria-roledescription', 'sortable');
      drag.setAttribute(
        'aria-keyshortcuts',
        'Control+ArrowUp Control+ArrowDown',
      );
      drag.setAttribute('aria-label', `Drag ${item.label}`);
      if (itemDisabled) drag.setAttribute('aria-disabled', 'true');

      const ico = document.createElement('i');
      ico.className = 'o9con o9con-drag-handle';
      ico.setAttribute('aria-hidden', 'true');
      drag.appendChild(ico);
      row.appendChild(drag);
    } else if (hasAnyDragHandle) {
      const spacer = document.createElement('span');
      spacer.className = 'arvo-hpop__opt__spacer';
      spacer.setAttribute('aria-hidden', 'true');
      row.appendChild(spacer);
    }

    if (showCheckSlot) {
      const checkSlot = document.createElement('span');
      checkSlot.className = 'arvo-hpop__opt__check';

      const ctrlEl = document.createElement('span');
      checkSlot.appendChild(ctrlEl);

      if (isMulti) {
        const cb = ArvoCheckbox.initialize(ctrlEl, {
          size: 'sm',
          isChecked,
          isIndeterminate: !!item.isIndeterminate,
          isExcluded: !!item.isExcluded,
          isDisabled: itemDisabled,
          value: item.id,
          onChange: () => this._handleToggleItem(item),
        });
        ctrlEl.setAttribute('aria-label', item.label);
        this._itemInstances.push(cb);
      } else {
        const rb = ArvoRadio.initialize(ctrlEl, {
          size: 'sm',
          name: this._id,
          value: item.id,
          isChecked,
          isDisabled: itemDisabled,
          onChange: () => this._handleToggleItem(item),
        });
        ctrlEl.setAttribute('aria-label', item.label);
        this._itemInstances.push(rb);
      }

      row.appendChild(checkSlot);
    }

    const lbl = document.createElement('span');
    lbl.className = 'arvo-hpop__opt__lbl';
    lbl.appendChild(document.createTextNode(item.label));
    if (item.secondaryLabel) {
      const sec = document.createElement('span');
      sec.className = 'arvo-hpop__opt__secondary';
      sec.textContent = item.secondaryLabel;
      lbl.appendChild(sec);
    }
    lbl.addEventListener('click', () => {
      if (itemDisabled) return;
      if (this._selection === 'none') return;
      this._handleToggleItem(item);
    });
    row.appendChild(lbl);

    if (showExclude) {
      const ex = document.createElement('span');
      ex.className = 'arvo-hpop__opt__exclude o9con o9con-exclude';
      ex.setAttribute('aria-label', 'Excluded');
      ex.setAttribute('role', 'img');
      row.appendChild(ex);
    }

    row.addEventListener('keydown', (event) => {
      if (event.key !== ' ' && event.key !== 'Enter') return;
      if (itemDisabled) return;
      if (this._selection === 'none') return;
      const target = event.target as HTMLElement;
      if (target !== row) {
        const interactive = target.closest('button, a, [role="button"]');
        if (interactive && interactive !== row) return;
      }
      event.preventDefault();
      this._handleToggleItem(item);
    });

    if (showInline) {
      const chevWrap = document.createElement('span');
      chevWrap.className = 'arvo-hpop__opt__chev';
      const chevEl = document.createElement('button') as HTMLButtonElement;
      const chev = ArvoIconButton.initialize(chevEl, {
        icon: 'angle-right',
        variant: 'tertiary',
        size: 'sm',
        tooltip: `Open ${item.label}`,
        isDisabled: itemDisabled,
        onClick: (e: Event) => {
          e.stopPropagation();
          // Inline nesting hook — recursive resolver is not implemented yet.
          // Consumers wire their own behavior in the future.
        },
      });
      chevWrap.appendChild(chevEl);
      row.appendChild(chevWrap);
      this._chevInstances.push(chev);
    }

    return row;
  }

  private _isItemChecked(item: HybridPopoverItem): boolean {
    if (this._selection === 'none') return false;
    if (this._selection === 'multi') {
      return Array.isArray(this._draft) && this._draft.includes(item.id);
    }
    return typeof this._draft === 'string' && this._draft === item.id;
  }

  // ---------------------------------------------------------------------------
  // Selection handlers
  // ---------------------------------------------------------------------------

  private _handleToggleItem(item: HybridPopoverItem): void {
    if (item.isDisabled) return;
    if (this._selection === 'none') return;

    let next: string[] | string | null;
    if (this._selection === 'multi') {
      const arr = Array.isArray(this._draft) ? [...this._draft] : [];
      const idx = arr.indexOf(item.id);
      next = idx === -1 ? [...arr, item.id] : arr.filter((v) => v !== item.id);
    } else {
      next = this._draft === item.id ? null : item.id;
    }
    this._updateDraft(next, { item, action: 'toggle' });
  }

  private _handleToggleGlobalSelectAll(): void {
    if (this._selection !== 'multi') return;
    const flatAll = flattenItems(this._items);
    const enabled = flatAll.filter((i) => !i.isDisabled).map((i) => i.id);
    if (enabled.length === 0) return;
    const arr = Array.isArray(this._draft) ? this._draft : [];
    const allSelected = enabled.every((id) => arr.includes(id));
    const next = allSelected
      ? arr.filter((id) => !enabled.includes(id))
      : Array.from(new Set([...arr, ...enabled]));
    this._updateDraft(next, { item: null, action: 'select-all' });
  }

  private _handleToggleGroupSelectAll(group: HybridPopoverGroup): void {
    if (this._selection !== 'multi') return;
    const enabled = group.items.filter((i) => !i.isDisabled).map((i) => i.id);
    if (enabled.length === 0) return;
    const arr = Array.isArray(this._draft) ? this._draft : [];
    const allSelected = enabled.every((id) => arr.includes(id));
    const next = allSelected
      ? arr.filter((id) => !enabled.includes(id))
      : Array.from(new Set([...arr, ...enabled]));
    this._updateDraft(next, { item: null, action: 'group-select-all' });
  }

  private _updateDraft(
    next: string[] | string | null,
    meta: HybridPopoverChangeMeta,
  ): void {
    this._draft = next;
    if ((this._options.commitOn ?? 'apply') === 'change') {
      this._committed = cloneValue(next);
      this._fireChange(next, meta);
      this._dispatchEvent('hpop:change', { value: cloneValue(next) });
    }
    this._renderBodyAndRewireDnD();
  }

  private _renderBodyAndRewireDnD(): void {
    this._renderBody();
    if (this.isOpen()) {
      this._teardownSortable();
      this._mountSortable();
      this._teardownRoving();
      this._mountRoving();
    }
  }

  // ---------------------------------------------------------------------------
  // Footer actions
  // ---------------------------------------------------------------------------

  private _buildPopoverActions(): ArvoPopoverActionConfig[] {
    if (this._options.actions === false) return [];
    if (this._options.actions) return this._options.actions;
    return [
      {
        id: 'reset',
        label: 'Reset',
        variant: 'tertiary',
        action: () => {
          this._handleReset();
          return false;
        },
      },
      {
        id: 'cancel',
        label: 'Cancel',
        variant: 'secondary',
        action: () => this._handleCancel(),
      },
      {
        id: 'apply',
        label: 'Apply',
        variant: 'primary',
        action: () => this._handleApply(),
      },
    ];
  }

  private _handleApply(): boolean | void {
    const next = cloneValue(this._draft);
    const result = this._options.onApply?.(next);
    this._committed = next;
    this._fireChange(next, { item: null, action: 'apply' });
    this._dispatchEvent('hpop:apply', { value: cloneValue(next) });
    if (result === false) return false;
    return undefined;
  }

  private _handleCancel(): void {
    this._draft = defaultDraft(this._selection, this._committed);
    this._query = '';
    this._renderSticky();
    this._renderBodyAndRewireDnD();
    this._options.onCancel?.();
    this._dispatchEvent('hpop:cancel', {});
    // Returning undefined → Popover auto-closes.
  }

  private _handleReset(): void {
    const cleared = this._selection === 'multi' ? [] : null;
    this._draft = cleared as string[] | string | null;
    this._query = '';
    if ((this._options.commitOn ?? 'apply') === 'change') {
      this._committed = cloneValue(this._draft);
      this._fireChange(this._draft, { item: null, action: 'reset' });
    }
    this._renderSticky();
    this._renderBodyAndRewireDnD();
    this._options.onReset?.();
    this._dispatchEvent('hpop:reset', {});
  }

  // ---------------------------------------------------------------------------
  // Search
  // ---------------------------------------------------------------------------

  private _handleSearchInput(value: string): void {
    this._query = value;
    // Re-render body for filtered list; sticky may need counter update.
    this._renderBodyAndRewireDnD();
    this._applyPanelClasses();
    this._updateSearchCounter();
  }

  private _handleSearchClear(): void {
    this._query = '';
    if (this._searchInstance) {
      this._searchInstance.value('');
    }
    this._renderBodyAndRewireDnD();
    this._applyPanelClasses();
    this._updateSearchCounter();
  }

  private _updateSearchCounter(): void {
    if (!this._searchInstance) return;
    const searchCfg =
      this._options.search && typeof this._options.search === 'object'
        ? (this._options.search as HybridPopoverSearchConfig)
        : null;
    if (!searchCfg?.counter) return;
    if (!this._query) return;
    const flatAll = flattenItems(this._items);
    const filteredCount = this._getFilteredItems().__filteredCount;
    this._searchInstance.counter(filteredCount, flatAll.length);
  }

  // ---------------------------------------------------------------------------
  // DnD adapter
  // ---------------------------------------------------------------------------

  private _mountSortable(): void {
    if (this._sortable) return;
    if (!this._options.enableReorder) return;
    if (this._isLoading) return;
    const list = this._bodyEl?.querySelector<HTMLElement>('.arvo-hpop__list');
    if (!list) return;

    this._sortable = createSortableList(list, {
      itemSelector: '.arvo-hpop__opt',
      handleSelector: '.arvo-hpop__opt__drag',
      getGroupOf: (el) => el.dataset.group ?? null,
      allowCrossGroup: !!this._options.crossGroupDrag,
      onCommit: (fromIndex, toIndex, fromGroup, toGroup) => {
        const next = applyReorder(
          this._items,
          fromIndex,
          toIndex,
          fromGroup,
          toGroup,
        );
        if (!this._isControlledItems) {
          this._items = next;
          // Re-render the body so the DOM reflects the new order then
          // remount sortable against the fresh nodes.
          this._renderBody();
          this._teardownSortable();
          this._mountSortable();
          this._teardownRoving();
          this._mountRoving();
        }
        this._options.onReorder?.({
          fromIndex,
          toIndex,
          fromGroup,
          toGroup,
          items: next,
        });
        this._dispatchEvent('hpop:reorder', {
          fromIndex,
          toIndex,
          fromGroup,
          toGroup,
        });
      },
    });
  }

  private _teardownSortable(): void {
    this._sortable?.destroy();
    this._sortable = null;
  }

  // ---------------------------------------------------------------------------
  // Resize adapter
  // ---------------------------------------------------------------------------

  private _mountResize(): void {
    if (this._resize) return;
    if (this._options.isResizable === false) return;
    const panel = this._panelEl;
    if (!panel) return;

    this._resize = createResizeHandle(panel, {
      corners: ['bottom-left', 'bottom-right'],
      min: { width: HPOP_MIN_WIDTH, height: HPOP_MIN_HEIGHT },
      max: (rect: DOMRect) => ({
        width: Math.max(
          HPOP_MIN_WIDTH,
          Math.min(HPOP_MAX_WIDTH, window.innerWidth - rect.left - 16),
        ),
        height: Math.max(
          HPOP_MIN_HEIGHT,
          Math.min(
            Math.floor(window.innerHeight * 0.9),
            window.innerHeight - rect.top - 16,
          ),
        ),
      }),
      viewportPadding: 16,
      onResize: (rect) => {
        this._resizedWidth = rect.width;
        this._resizedHeight = rect.height;
        this._options.onResize?.(rect);
      },
      onCommit: (rect) => {
        this._resizedWidth = rect.width;
        this._resizedHeight = rect.height;
        this._options.onResizeCommit?.(rect);
        this._popover?.reposition();
      },
    });
    this._resize.mount();
  }

  private _teardownResize(): void {
    this._resize?.destroy();
    this._resize = null;
  }

  // ---------------------------------------------------------------------------
  // Roving tabindex adapter
  // ---------------------------------------------------------------------------

  private _mountRoving(): void {
    if (this._roving) return;
    if (this._isLoading) return;
    const list = this._bodyEl?.querySelector<HTMLElement>('.arvo-hpop__list');
    if (!list) return;

    const items = this._collectRovingItems(list);
    if (items.length === 0) return;

    this._roving = createTabRoving();
    this._roving.activate({
      container: list,
      items,
      orientation: 'vertical',
      wrap: false,
    });

    // Strip native checkbox / radio inputs from the tab order — the row
    // owns the single Tab stop and Space/Enter delegates the toggle.
    list
      .querySelectorAll<HTMLInputElement>(
        '.arvo-checkbox__input, .arvo-radio__input',
      )
      .forEach((input) => {
        input.tabIndex = -1;
      });
  }

  private _teardownRoving(): void {
    this._roving?.deactivate();
    this._roving = null;
  }

  private _collectRovingItems(list: HTMLElement): HTMLElement[] {
    const sa = Array.from(
      list.querySelectorAll<HTMLElement>('.arvo-hpop__sa'),
    ).filter((el) => el.getAttribute('aria-disabled') !== 'true');
    const opts = Array.from(
      list.querySelectorAll<HTMLElement>('.arvo-hpop__opt'),
    ).filter((el) => el.getAttribute('aria-disabled') !== 'true');
    return [...sa, ...opts];
  }

  // ---------------------------------------------------------------------------
  // Inner instance teardown
  // ---------------------------------------------------------------------------

  private _destroyBodyInstances(): void {
    this._globalSAInstance?.destroy();
    this._globalSAInstance = null;
    this._groupSAInstances.forEach((i) => i.destroy());
    this._groupSAInstances = [];
    this._itemInstances.forEach((i) => i.destroy());
    this._itemInstances = [];
    this._chevInstances.forEach((i) => i.destroy());
    this._chevInstances = [];
    this._clearSearchInstance?.destroy();
    this._clearSearchInstance = null;
  }

  private _destroyInnerInstances(): void {
    this._searchInstance?.destroy();
    this._searchInstance = null;
    this._conditionalInstance?.destroy();
    this._conditionalInstance = null;
    this._destroyBodyInstances();
  }

  // ---------------------------------------------------------------------------
  // Internal helpers
  // ---------------------------------------------------------------------------

  private _fireChange(
    value: string[] | string | null,
    meta: HybridPopoverChangeMeta,
  ): void {
    this._options.onChange?.(cloneValue(value), meta);
  }

  private _dispatchEvent(name: string, detail: Record<string, unknown>): void {
    this._trigger?.dispatchEvent(
      new CustomEvent(name, { bubbles: true, cancelable: true, detail }),
    );
  }
}

export default ArvoHybridPopover;
